"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import Link from "next/link";
import { Loader2, ArrowRight } from "lucide-react";
import Image from "next/image";

export default function LoginPage() {
  const [loading, setLoading] = useState(false);
  const router = useRouter();
  const { toast } = useToast();

  const [formData, setFormData] = useState({
    username: "",
    password: "",
  });

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);

    // Mock Login Logic
    setTimeout(() => {
      const users = JSON.parse(localStorage.getItem('users') || '[]');
      
      // Hardcoded Admin
      if (formData.username === 'admin' && formData.password === 'ADMIN@2026') {
        const adminUser = { uid: 'admin-1', email: 'admin', role: 'admin' };
        localStorage.setItem('currentUser', JSON.stringify(adminUser));
        toast({ title: "Welcome Admin!" });
        router.push("/dashboard");
        setLoading(false);
        return;
      }

      const found = users.find((u: any) => u.id === formData.username && u.password === formData.password);

      if (found) {
        localStorage.setItem('currentUser', JSON.stringify(found));
        toast({ title: "Welcome back!", description: "Successfully logged in." });
        router.push("/dashboard");
      } else {
        toast({ variant: "destructive", title: "Login Failed", description: "Invalid username or password." });
      }
      setLoading(false);
    }, 1000);
  };

  return (
    <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 p-4">
      <div className="w-full max-w-4xl">
        <div className="text-center mb-8">
            <Image src="/logo.png" alt="AMA Student Portal" width={200} height={50} className="mx-auto" />
        </div>
        <div className="grid md:grid-cols-2 rounded-2xl shadow-2xl overflow-hidden">
          <div className="bg-red-600 text-white p-12 flex flex-col justify-center">
            <h2 className="text-4xl font-bold mb-4">WELCOME TO STUDENT PORTAL</h2>
            <p className="text-red-100">
              A wise man will hear, and will increase learning; and a man of understanding shall attain unto wise counsels.
            </p>
          </div>
          <div className="bg-white p-12">
            <h3 className="text-2xl font-semibold mb-2 text-gray-800">WELCOME BACK</h3>
            <p className="text-gray-500 mb-8">Please sign in to continue</p>
            <form onSubmit={handleLogin} className="space-y-6">
              <div className="space-y-2">
                <Label htmlFor="username">USN/EMP</Label>
                <Input 
                  id="username"
                  type="text" 
                  placeholder="admin" 
                  required 
                  value={formData.username} 
                  onChange={e => setFormData({...formData, username: e.target.value})} 
                />
              </div>
              <div className="space-y-2">
                <Label htmlFor="password">Password</Label>
                <Input 
                  id="password"
                  type="password" 
                  placeholder="ADMIN@2026"
                  required 
                  value={formData.password} 
                  onChange={e => setFormData({...formData, password: e.target.value})} 
                />
              </div>
              <Button type="submit" className="w-full bg-red-600 hover:bg-red-700 mt-4 text-white font-bold py-3 flex items-center justify-center gap-2" disabled={loading}>
                {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : <>Sign In <ArrowRight className="h-4 w-4" /></>}
              </Button>
            </form>
            <p className="text-center text-sm text-gray-500 mt-8">
              Don't have an account? <Link href="/register" className="font-semibold text-red-600 hover:underline">Sign up</Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
